import React, { useState, useEffect, useCallback } from 'react';

export default function ImageGallery({ images }) {
  const [index, setIndex] = useState(null);

  const close = useCallback(() => setIndex(null), []);
  const prev = useCallback(() => setIndex((i) => (i - 1 + images.length) % images.length), [images.length]);
  const next = useCallback(() => setIndex((i) => (i + 1) % images.length), [images.length]);

  useEffect(() => {
    if (index === null) return;
    const onKey = (e) => {
      if (e.key === 'Escape') close();
      else if (e.key === 'ArrowRight') next();
      else if (e.key === 'ArrowLeft') prev();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [index, close, prev, next]);

  return (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 8, maxWidth: 360 }}>
        {images.map((img, i) => (
          <button
            key={i}
            onClick={() => setIndex(i)}
            aria-label={`Open image ${i + 1}`}
            style={{ height: 90, border: 'none', borderRadius: 8, cursor: 'pointer', background: img }}
          />
        ))}
      </div>

      {index !== null && (
        <div
          onClick={close}
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }}
        >
          <button onClick={(e) => { e.stopPropagation(); prev(); }} style={navBtn('left')} aria-label="Previous">‹</button>
          <div
            onClick={(e) => e.stopPropagation()}
            style={{ width: 'min(70vw, 480px)', height: 'min(60vh, 360px)', borderRadius: 12, background: images[index], boxShadow: '0 10px 40px rgba(0,0,0,0.5)' }}
          />
          <button onClick={(e) => { e.stopPropagation(); next(); }} style={navBtn('right')} aria-label="Next">›</button>
          <button onClick={close} style={{ position: 'fixed', top: 16, right: 20, fontSize: 28, color: '#fff', background: 'none', border: 'none', cursor: 'pointer' }} aria-label="Close">✕</button>
          <span style={{ position: 'fixed', bottom: 20, color: '#fff' }}>{index + 1} / {images.length}</span>
        </div>
      )}
    </div>
  );
}

function navBtn(side) {
  return {
    position: 'fixed',
    [side]: 20,
    top: '50%',
    transform: 'translateY(-50%)',
    fontSize: 40,
    color: '#fff',
    background: 'none',
    border: 'none',
    cursor: 'pointer',
  };
}

angular.answer:
## Building an Image Gallery with Lightbox in Angular

**Mental model:** A thumbnail grid plus an overlay showing one image, driven by a single nullable *index* (`null` = closed). Prev/next wrap with modulo; Escape and backdrop click close. Classic `NgModule` setup, no `?.`/`??` (the build rejects them).

### Step 1 — Open index
```typescript
index: number | null = null;
close(): void { this.index = null; }
```

### Step 2 — Prev / next with wrap
```typescript
prev(): void { this.index = (this.index! - 1 + this.images.length) % this.images.length; }
next(): void { this.index = (this.index! + 1) % this.images.length; }
```

### Step 3 — Keyboard while open
```typescript
@HostListener('document:keydown', ['$event'])
onKey(e: KeyboardEvent): void {
  if (this.index === null) { return; }
  if (e.key === 'Escape') { this.close(); }
  if (e.key === 'ArrowRight') { this.next(); }
  if (e.key === 'ArrowLeft') { this.prev(); }
}
```

### Step 4 — Overlay with backdrop close
```html
<div *ngIf="index !== null" (click)="close()">
  <div [style.background]="images[index]" (click)="$event.stopPropagation()"></div>
</div>
```

**Edge cases**

| Case | Handling |
| :-- | :-- |
| Wrap at ends | Modulo. |
| Backdrop vs image | `stopPropagation` on the frame. |
| Listener | `@HostListener` auto-unbinds on destroy. |

**Interview tip:** A single nullable index models open + current image at once; `@HostListener('document:keydown')` keeps the arrow/escape handling declarative and auto-cleaned-up.

