import { Component, HostListener } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-image-gallery',
  template: `
    <div>
      <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; max-width: 360px;">
        <button
          *ngFor="let img of images; let i = index"
          (click)="open(i)"
          [attr.aria-label]="'Open image ' + (i + 1)"
          [style.background]="img"
          style="height: 90px; border: none; border-radius: 8px; cursor: pointer;"
        ></button>
      </div>

      <div
        *ngIf="index !== null"
        (click)="close()"
        style="position: fixed; inset: 0; background: rgba(0,0,0,0.8); display: flex; align-items: center; justify-content: center; z-index: 1000;"
      >
        <button (click)="$event.stopPropagation(); prev()" aria-label="Previous" style="position: fixed; left: 20px; top: 50%; transform: translateY(-50%); font-size: 40px; color: #fff; background: none; border: none; cursor: pointer;">‹</button>
        <div
          (click)="$event.stopPropagation()"
          [style.background]="images[index]"
          style="width: min(70vw, 480px); height: min(60vh, 360px); border-radius: 12px; box-shadow: 0 10px 40px rgba(0,0,0,0.5);"
        ></div>
        <button (click)="$event.stopPropagation(); next()" aria-label="Next" style="position: fixed; right: 20px; top: 50%; transform: translateY(-50%); font-size: 40px; color: #fff; background: none; border: none; cursor: pointer;">›</button>
        <button (click)="close()" aria-label="Close" style="position: fixed; top: 16px; right: 20px; font-size: 28px; color: #fff; background: none; border: none; cursor: pointer;">✕</button>
        <span style="position: fixed; bottom: 20px; color: #fff;">{{ index + 1 }} / {{ images.length }}</span>
      </div>
    </div>
  `,
})
export class ImageGalleryComponent {
  index: number | null = null;
  images = [
    'linear-gradient(135deg,#2563eb,#7c3aed)',
    'linear-gradient(135deg,#16a34a,#22d3ee)',
    'linear-gradient(135deg,#d97706,#dc2626)',
    'linear-gradient(135deg,#7c3aed,#ec4899)',
    'linear-gradient(135deg,#0891b2,#14b8a6)',
    'linear-gradient(135deg,#f59e0b,#ef4444)',
  ];

  open(i: number): void {
    this.index = i;
  }

  close(): void {
    this.index = null;
  }

  prev(): void {
    if (this.index === null) {
      return;
    }
    this.index = (this.index - 1 + this.images.length) % this.images.length;
  }

  next(): void {
    if (this.index === null) {
      return;
    }
    this.index = (this.index + 1) % this.images.length;
  }

  @HostListener('document:keydown', ['$event'])
  onKey(e: KeyboardEvent): void {
    if (this.index === null) {
      return;
    }
    if (e.key === 'Escape') {
      this.close();
    } else if (e.key === 'ArrowRight') {
      this.next();
    } else if (e.key === 'ArrowLeft') {
      this.prev();
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Image Gallery Demo</h1>
      <app-image-gallery></app-image-gallery>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, ImageGalleryComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
